void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        using var transaction = db.Database.BeginTransaction();
        db.Database.Migrate();
        transaction.Commit();
    });
}

arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 manages its own transactions and execution strategy during Migrate().
    // Wrapping in an explicit transaction now throws.
    db.Database.Migrate();
}

